#include<bits/stdc++.h>
using namespace std;
int v[1001],v2[10001],y[3];
int main(){
    int a,b,c,d;
    cin>>a>>b>>c>>d;
    for(int i=0;i<a;i++){
        v[i]++;
    }
    for(int i=0;i<c;i++){
        v2[i]++;
    }
    cin>>y[0]>>y[1]>>y[2];
    y[0]--;
    y[1]--;
    y[2]--;
    for(int i=0;i<=2;i++){
        int n=y[i]%(a+b);
        int m=y[i]%(c+d);
        int x=v[n]+v2[m];
        if(x>=2){
            cout<<"both\n";
        }else if(x==1){
            cout<<"one\n";
        }else{
            cout<<"none\n";
        }
    }
}
